package com.infy.inventrack.user.entity; import com.infy.inventrack.common.enums.UserRole; import jakarta.persistence.*; import lombok.*; @Getter @Setter @NoArgsConstructor @Entity @Table(name="users") public class AppUser { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Integer userId; @Column(nullable=false,unique=true,length=50) private String userName; @Column(nullable=false) private String password; @Column(nullable=false,unique=true) private String email; @Enumerated(EnumType.STRING) @Column(nullable=false,length=20) private UserRole role; }
